module RefModule(
	input signed [2:0] A,
	input signed [2:0] B,
	input carry_in,
	output signed [3:0] Sum  
	);  wire _n01 = A + B[0] ^ $signed({1'b0, carry_in})[0];
  wire _c01 = A + B[0] & $signed({1'b0, carry_in})[0];
  wire _n02 = A + B[1] ^ $signed({1'b0, carry_in})[1] ^ _c01;
  wire _c02 = (A + B[1] & $signed({1'b0, carry_in})[1]) | (A + B[1] & _c01) | ($signed({1'b0, carry_in})[1] & _c01);
  wire _n03 = A + B[2] ^ $signed({1'b0, carry_in})[2] ^ _c02;
  wire _c03 = (A + B[2] & $signed({1'b0, carry_in})[2]) | (A + B[2] & _c02) | ($signed({1'b0, carry_in})[2] & _c02);
  wire _n04 = A + B[3] ^ $signed({1'b0, carry_in})[3] ^ _c03;
  wire _c04 = (A + B[3] & $signed({1'b0, carry_in})[3]) | (A + B[3] & _c03) | ($signed({1'b0, carry_in})[3] & _c03);
  assign Sum = {_n01, _n02, _n03, _n04};
endmodule
